css:
.loader { --speed: var(--loader-speed); --accent: var(--loader-color); --accent-2: var(--loader-secondary-color); width: calc(var(--loader-size) * 2.8); height: var(--loader-size); min-width: 170px; position: relative; overflow: hidden; }
.belt { position: absolute; left: 0; right: 0; bottom: 18%; height: 18%; border-radius: 999px; background: repeating-linear-gradient(90deg, #1f2937 0 20px, #334155 20px 40px); animation: belt-run calc(var(--speed) * .7) linear infinite; box-shadow: inset 0 5px #ffffff18; }
.box { position: absolute; bottom: 36%; width: 22%; aspect-ratio: 1.05; border-radius: 8px 8px 4px 4px; background: linear-gradient(135deg, var(--accent), var(--accent-2)); box-shadow: inset 0 -8px #0002, 0 10px 18px #02061744; animation: box-run calc(var(--speed) * 3.2) linear infinite; }
.box::before { content: ""; position: absolute; inset: 0 43%; background: #fff6; }
.box-a { left: -28%; } .box-b { left: -28%; animation-delay: calc(var(--speed) * -1.05); } .box-c { left: -28%; animation-delay: calc(var(--speed) * -2.1); }
@keyframes box-run { 0% { transform: translateX(0) rotate(-6deg); } 50% { transform: translateX(calc(var(--loader-size) * 1.55)) rotate(4deg); } 100% { transform: translateX(calc(var(--loader-size) * 3.4)) rotate(-6deg); } }
@keyframes belt-run { to { background-position: -40px 0; } }
